fun solve(s: String): String {
    val vowels = setOf('a', 'e', 'i', 'o', 'u')

    // Data structure to hold information about each unique vowel: count and first index
    val vowelInfo = mutableMapOf<Char, Pair<Int, Int>>() // Map<Vowel, Pair<Count, FirstIndex>>
    // List to store the original indices where vowels appear in s
    val vowelIndices = mutableListOf<Int>()

    for (i in s.indices) {
        val char = s[i]
        if (char in vowels) {
            vowelIndices.add(i)

            if (!vowelInfo.containsKey(char)) {
                // Initialize: Count = 1, FirstIndex = i
                vowelInfo[char] = Pair(1, i)
            } else {
                // Update count
                val (currentCount, firstIndex) = vowelInfo[char]!!
                vowelInfo[char] = Pair(currentCount + 1, firstIndex)
            }
        }
    }

    // Get a list of unique vowels present
    var uniqueVowels = vowelInfo.keys.toList()

    // Sorting logic:
    // 1. Primary sort key: Frequency (non-increasing/descending)
    // 2. Secondary sort key: First appearance index (ascending/increasing)
    uniqueVowels.sortWith(Comparator { a, b ->
        val (countA, firstIndexA) = vowelInfo[a]!!
        val (countB, firstIndexB) = vowelInfo[b]!!

        // Compare frequencies (descending: B - A)
        if (countB != countA) {
            countB - countA
        } else {
            // Frequencies are equal, compare first appearance index (ascending: A - B)
            firstIndexA - firstIndexB
        }
    })

    // 3. Construct the sorted sequence of all vowels
    val sortedVowelSequence = mutableListOf<Char>()
    for (vowel in uniqueVowels) {
        val (count, _) = vowelInfo[vowel]!!
        repeat(count) {
            sortedVowelSequence.add(vowel)
        }
    }

    // 4. Replace the vowels in place using the sorted sequence
    val sChars = s.toCharArray()

    // Replace the vowel at the original index with the next vowel from the sorted sequence
    for (i in vowelIndices.indices) {
        val originalIndex = vowelIndices[i]
        sChars[originalIndex] = sortedVowelSequence[i]
    }

    return String(sChars)
}
