    const vowelInfo = new Map(); // Maps vowel character to {count: number, firstIndex: number}
    const vowelIndices = [];     // Stores indices where vowels appear in s

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            vowelIndices.push(i);

            if (!vowelInfo.has(char)) {
                vowelInfo.set(char, { count: 0, firstIndex: i });
            }

            // Update count
            const info = vowelInfo.get(char);
            info.count++;
        }
